"""requests.models — Request/Response objects."""
import json as _json
from requests.structures import CaseInsensitiveDict
from requests import exceptions

class Request:
    def __init__(self, method=None, url=None, headers=None, data=None, params=None, json=None, auth=None, cookies=None):
        self.method = method
        self.url = url
        self.headers = CaseInsensitiveDict(headers or {})
        self.data = data
        self.params = params
        self.json = json
        self.auth = auth
        self.cookies = cookies

class PreparedRequest:
    def __init__(self):
        self.method = None
        self.url = None
        self.headers = CaseInsensitiveDict()
        self.body = None

class Response:
    def __init__(self):
        self.status_code = None
        self._content = b""
        self.headers = CaseInsensitiveDict()
        self.url = ""
        self.encoding = "utf-8"
        self.reason = ""
        self.elapsed = None
        self.request = None
        self.cookies = {}

    @property
    def ok(self):
        return self.status_code is not None and self.status_code < 400

    @property
    def text(self):
        enc = self.encoding or "utf-8"
        try:
            return self._content.decode(enc)
        except (UnicodeDecodeError, LookupError):
            return self._content.decode("utf-8", errors="replace")

    @property
    def content(self):
        return self._content

    def json(self, **kwargs):
        try:
            return _json.loads(self.text, **kwargs)
        except _json.JSONDecodeError as e:
            raise exceptions.JSONDecodeError(str(e))

    def raise_for_status(self):
        if self.status_code and self.status_code >= 400:
            raise exceptions.HTTPError(
                f"{self.status_code} {self.reason} for url: {self.url}",
                response=self
            )

    def iter_content(self, chunk_size=1024):
        for i in range(0, len(self._content), chunk_size):
            yield self._content[i:i+chunk_size]

    def iter_lines(self, chunk_size=512, delimiter=None):
        pending = b""
        for chunk in self.iter_content(chunk_size):
            pending += chunk
            sep = delimiter or b"\n"
            while sep in pending:
                line, pending = pending.split(sep, 1)
                yield line
        if pending:
            yield pending

    def __repr__(self):
        return f"<Response [{self.status_code}]>"

    def __bool__(self):
        return self.ok
